import axios from 'axios';

const BASE = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';
const api = axios.create({ baseURL: BASE });

// Suites
export const getSuites   = ()       => api.get('/suites').then(r => r.data);
export const getSuite    = (id)     => api.get(`/suites/${id}`).then(r => r.data);
export const createSuite = (data)   => api.post('/suites', data).then(r => r.data);
export const updateSuite = (id, d)  => api.put(`/suites/${id}`, d).then(r => r.data);
export const deleteSuite = (id)     => api.delete(`/suites/${id}`).then(r => r.data);

// Parse
export const parsePlaywright = (code) =>
  api.post('/parse', { code }).then(r => r.data);

// Generate (SSE streaming — returns raw fetch Response)
export const generateScriptStream = (payload) => {
  return fetch(`${BASE}/generate`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload),
  });
};

// Run
export const runSuite   = (id)      => api.post(`/suites/${id}/run`).then(r => r.data);
export const runStatus  = (sid,rid) => api.get(`/suites/${sid}/run/status/${rid}`).then(r => r.data);

// Results
export const getResults  = (params) => api.get('/results', { params }).then(r => r.data);
export const patchResult = (id, d)  => api.patch(`/results/${id}`, d).then(r => r.data);
